import zeep

# Define WSDL URL of third-party insurance service
wsdl_url = 'https://example.com/insurance-service?wsdl'

# Create a new Zeep client instance
client = zeep.Client(wsdl=wsdl_url)

def get_policy_details(policy_number, customer_name):
    # Construct SOAP request body with user-provided values
    soap_body = f'''
        <ns0:GetPolicyDetails xmlns:ns0="http://example.com/insurance-service">
            <ns0:policyNumber>{policy_number}</ns0:policyNumber>
            <ns0:customerName>{customer_name}</ns0:customerName>
        </ns0:GetPolicyDetails>
    '''

    # Send SOAP request to third-party insurance service
    response = client.service.GetPolicyDetails(soap_body)

    return response

def main():
    policy_number = input("Enter policy number: ")
    customer_name = input("Enter customer name: ")

    try:
        result = get_policy_details(policy_number, customer_name)
        print(result)
    except Exception as e:
        print(f"Error: {e}")

if __name__ == "__main__":
    main()